// ══════════════════════════════════════════
// EXTRACT & VALIDATE MESSAGE — v4 Multi-Tenant
// ══════════════════════════════════════════
const data = $input.first().json;

const entry    = data?.body?.entry?.[0] || data?.entry?.[0];
const change   = entry?.changes?.[0]?.value;
const messages = data?.messages?.[0] || change?.messages?.[0];
const contacts = data?.contacts?.[0]  || change?.contacts?.[0];
const statuses = data?.statuses?.[0]  || change?.statuses?.[0];
const metadata = change?.metadata || {};

if (statuses && !messages) return [{ json: { skip: true, reason: 'status_event' } }];
if (!messages)             return [{ json: { skip: true, reason: 'no_message' } }];

const from        = messages?.from || '';
const name        = contacts?.profile?.name || 'مستخدم';
const messageId   = messages?.id || '';
const messageType = messages?.type || 'text';

// ── Multi-tenant: identify which WhatsApp number received the message ──
const tenantPhoneId = metadata?.phone_number_id || $env.WHATSAPP_PHONE_NUMBER_ID || 'default';
const tenantId      = tenantPhoneId;

let messageText = '';
if (messageType === 'text') {
  messageText = messages?.text?.body || '';
} else if (messageType === 'audio') {
  messageText = `[VOICE:${messages?.audio?.id || ''}]`;
} else if (messageType === 'image') {
  const caption = messages?.image?.caption || '';
  messageText = `[IMAGE:${messages?.image?.id || ''}${caption ? ':' + caption : ''}]`;
} else if (messageType === 'document') {
  messageText = '[مستند]';
} else if (messageType === 'location') {
  const loc = messages?.location;
  messageText = loc ? `[موقع: ${loc.latitude}, ${loc.longitude}]` : '[موقع]';
} else {
  messageText = '[رسالة غير مدعومة]';
}

if (!from) return [{ json: { skip: true, reason: 'no_sender' } }];
if (!messageText.trim()) return [{ json: { skip: true, reason: 'empty_message' } }];

const maxLen = parseInt($env.MAX_MESSAGE_LENGTH || '2000');
if (messageText.length > maxLen) messageText = messageText.substring(0, maxLen) + '...';
messageText = messageText.replace(/<[^>]*>/g, '');

return [{
  json: {
    tenant_id:    tenantId,
    user_id:      `${tenantId}:${from}`,
    phone_number: from,
    user_name:    name,
    message:      messageText,
    msg_type:     messageType,
    message_id:   messageId,
    timestamp:    new Date().toISOString(),
    raw_audio_id: messageType === 'audio' ? messages?.audio?.id : null,
    raw_image_id: messageType === 'image' ? messages?.image?.id : null,
    skip: false
  }
}];

// ══════════════════════════════════════════
// VERIFY WEBHOOK SIGNATURE — v6.2
// ✅ FIX: n8n WhatsApp Trigger node handles
//    signature verification automatically.
//    This node adds extra app-secret check
//    only when called via generic webhook.
// ══════════════════════════════════════════
const crypto = require('crypto');
const data   = $input.first().json;

const appSecret = $env.WHATSAPP_APP_SECRET || '';
const sigHeader = $input.first()?.headers?.['x-hub-signature-256'] || '';

// ── اذا مافي secret مضبوط — اسمح بالمرور ──
// (n8n WhatsApp Trigger يتحقق تلقائياً)
if (!appSecret) {
  return [$input.first()];
}

// ── اذا مافي signature header — اسمح بالمرور ──
// WhatsApp Trigger يكون قد تحقق منها بالفعل
if (!sigHeader) {
  return [$input.first()];
}

// ── تحقق إضافي للـ Generic Webhook فقط ──
// نستخدم rawBody اذا متوفر، وإلا نتجاوز
const rawBody = $input.first()?.rawBody || '';
if (!rawBody) {
  // rawBody غير متوفر في WhatsApp Trigger — تجاوز
  return [$input.first()];
}

try {
  const expectedSig = 'sha256=' + crypto
    .createHmac('sha256', appSecret)
    .update(rawBody)
    .digest('hex');

  const sigBuffer      = Buffer.from(sigHeader);
  const expectedBuffer = Buffer.from(expectedSig);

  if (sigBuffer.length !== expectedBuffer.length) {
    console.error('Signature length mismatch');
    return [{ json: { skip: true, reason: 'invalid_signature' } }];
  }

  const valid = crypto.timingSafeEqual(sigBuffer, expectedBuffer);
  if (!valid) {
    console.error('Signature mismatch — possible spoofed request');
    return [{ json: { skip: true, reason: 'invalid_signature' } }];
  }
} catch(e) {
  // أي خطأ في التحقق — اسمح بالمرور (WhatsApp Trigger تحقق بالفعل)
  console.warn('Signature check error (non-fatal):', e.message);
}

return [$input.first()];

// ══════════════════════════════════════════
// SEND READ RECEIPT + TYPING INDICATOR — v6.1
// FIX: uses tenant_id for multi-tenant phone routing
// ══════════════════════════════════════════
const d       = $input.first().json;
const token   = $env.WHATSAPP_ACCESS_TOKEN;
const phoneId = d.tenant_id || $env.WHATSAPP_PHONE_NUMBER_ID;
const base    = `https://graph.facebook.com/v18.0/${phoneId}/messages`;

try {
  // 1. Mark message as read
  await $http.request({
    method: 'POST',
    url: base,
    headers: { Authorization: `Bearer ${token}`, 'Content-Type': 'application/json' },
    body: JSON.stringify({
      messaging_product: 'whatsapp',
      status: 'read',
      message_id: d.message_id
    })
  });

  // 2. Send typing indicator
  await $http.request({
    method: 'POST',
    url: base,
    headers: { Authorization: `Bearer ${token}`, 'Content-Type': 'application/json' },
    body: JSON.stringify({
      messaging_product: 'whatsapp',
      recipient_type: 'individual',
      to: d.phone_number,
      type: 'reaction',
      reaction: { message_id: d.message_id, emoji: '⏳' }
    })
  });
} catch(e) {
  console.warn('Read receipt / typing failed (non-fatal):', e.message);
}

return [$input.first()];

// ══════════════════════════════════════════
// USER ONBOARDING — v4
// FIX: Check Supabase first, fallback to static data
// ══════════════════════════════════════════
const d = $input.first().json;
const token      = $env.WHATSAPP_ACCESS_TOKEN;
const phoneId    = d.tenant_id || $env.WHATSAPP_PHONE_NUMBER_ID;
const supaUrl    = $env.SUPABASE_URL || '';
const supaKey    = $env.SUPABASE_KEY || '';

try {
  let isNewUser = true;

  // Check Supabase first (persists across restarts)
  if (supaUrl && supaKey) {
    try {
      const r = await $http.request({
        method: 'GET',
        url: `${supaUrl}/rest/v1/users?user_id=eq.${encodeURIComponent(d.user_id)}&select=user_id,total_messages`,
        headers: { 'apikey': supaKey, 'Authorization': `Bearer ${supaKey}` }
      });
      const users = JSON.parse(r);
      if (users && users.length > 0 && users[0].total_messages > 0) {
        isNewUser = false;
      }
    } catch(e) {
      // Supabase unavailable — fallback to static data
      const state = $getWorkflowStaticData('global');
      if (!state.knownUsers) state.knownUsers = {};
      if (state.knownUsers[d.user_id]) isNewUser = false;
    }
  } else {
    // No Supabase — use static data
    const state = $getWorkflowStaticData('global');
    if (!state.knownUsers) state.knownUsers = {};
    if (state.knownUsers[d.user_id]) isNewUser = false;
    else state.knownUsers[d.user_id] = new Date().toISOString();
  }

  if (isNewUser) {
    const botName = $env.BOT_NAME || 'مساعد ذكي';
    const welcomeMsg = `أهلاً وسهلاً ${d.user_name}! 👋

أنا ${botName}. يمكنني مساعدتك في:

✅ *المهام والتذكيرات*
قل: "ذكرني بموعد الاجتماع الساعة 3"

💬 *الإجابة على أسئلتك*
اسألني أي شيء!

⚡ *تنفيذ الأوامر*
قل: "أرسل تقرير اليوم"

كيف يمكنني مساعدتك؟ 😊`;

    await $http.request({
      method: 'POST',
      url: `https://graph.facebook.com/v18.0/${phoneId}/messages`,
      headers: { Authorization: `Bearer ${token}`, 'Content-Type': 'application/json' },
      body: JSON.stringify({
        messaging_product: 'whatsapp',
        to: d.phone_number || d.user_id.split(':').pop(),
        type: 'text',
        text: { body: welcomeMsg, preview_url: false }
      })
    });
  }
} catch(e) {
  console.warn('Onboarding failed (non-fatal):', e.message);
}

return [$input.first()];

// ══════════════════════════════════════════
// VOICE TRANSCRIPTION  [NEW - Tier 3]
// Transcribes audio messages using Whisper API
// ══════════════════════════════════════════
const d = $input.first().json;

// Only process if it's a voice message and OpenAI key is configured
if (d.msg_type !== 'audio' || !$env.OPENAI_API_KEY || !d.raw_audio_id) {
  return [$input.first()];
}

try {
  const waToken = $env.WHATSAPP_ACCESS_TOKEN;
  const phoneId = $env.WHATSAPP_PHONE_NUMBER_ID;

  // Step 1: Get the media URL from WhatsApp
  const mediaResponse = await $http.request({
    method: 'GET',
    url: `https://graph.facebook.com/v18.0/${d.raw_audio_id}`,
    headers: { Authorization: `Bearer ${waToken}` }
  });
  const mediaUrl = JSON.parse(mediaResponse).url;

  // Step 2: Download the audio file
  const audioResponse = await $http.request({
    method: 'GET',
    url: mediaUrl,
    headers: { Authorization: `Bearer ${waToken}` },
    encoding: 'arraybuffer'
  });

  // Step 3: Send to Whisper for transcription
  const formData = new FormData();
  formData.append('file', new Blob([audioResponse], { type: 'audio/ogg' }), 'audio.ogg');
  formData.append('model', 'whisper-1');
  formData.append('language', 'ar');

  const transcriptResponse = await $http.request({
    method: 'POST',
    url: 'https://api.openai.com/v1/audio/transcriptions',
    headers: { Authorization: `Bearer ${$env.OPENAI_API_KEY}` },
    body: formData
  });

  const transcript = JSON.parse(transcriptResponse).text;
  console.log('Voice transcribed:', transcript);

  return [{ json: { ...d, message: transcript, original_type: 'audio' } }];
} catch(e) {
  console.warn('Voice transcription failed:', e.message);
  return [{ json: { ...d, message: '[رسالة صوتية — تعذّر التحويل]' } }];
}

// ══════════════════════════════════════════
// IMAGE ANALYSIS  [NEW - Tier 3]
// Analyzes images using Gemini Vision
// ══════════════════════════════════════════
const d = $input.first().json;

if (d.msg_type !== 'image' || !d.raw_image_id) {
  return [$input.first()];
}

try {
  const waToken = $env.WHATSAPP_ACCESS_TOKEN;
  const geminiKey = $env.GEMINI_API_KEY;

  // Step 1: Get media URL from WhatsApp
  const mediaResponse = await $http.request({
    method: 'GET',
    url: `https://graph.facebook.com/v18.0/${d.raw_image_id}`,
    headers: { Authorization: `Bearer ${waToken}` }
  });
  const mediaUrl = JSON.parse(mediaResponse).url;

  // Step 2: Download image as base64
  const imgResponse = await $http.request({
    method: 'GET',
    url: mediaUrl,
    headers: { Authorization: `Bearer ${waToken}` },
    encoding: 'base64'
  });

  // Step 3: Send to Gemini Vision
  const caption = d.message.includes(':') ? d.message.split(':').slice(2).join(':') : '';
  const prompt  = caption || 'صف هذه الصورة بالتفصيل وأخبرني بأهم ما فيها.';

  const visionResponse = await $http.request({
    method: 'POST',
    url: `https://generativelanguage.googleapis.com/v1beta/models/gemini-1.5-pro:generateContent?key=${geminiKey}`,
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      contents: [{
        parts: [
          { text: prompt },
          { inline_data: { mime_type: 'image/jpeg', data: imgResponse } }
        ]
      }],
      generationConfig: { maxOutputTokens: 500 }
    })
  });

  const analysis = JSON.parse(visionResponse)?.candidates?.[0]?.content?.parts?.[0]?.text || 'تعذّر تحليل الصورة.';
  return [{ json: { ...d, message: `[تحليل الصورة]: ${analysis}`, original_type: 'image' } }];
} catch(e) {
  console.warn('Image analysis failed:', e.message);
  return [{ json: { ...d, message: '[صورة — تعذّر التحليل]' } }];
}

// ══════════════════════════════════════════
// DEDUPLICATE + RATE LIMIT — v6
// ✅ Uses Redis for persistence across n8n restarts
//    Falls back to static data if Redis not configured
// ══════════════════════════════════════════
const d          = $input.first().json;
const now        = Date.now();
const rateLimit  = parseInt($env.RATE_LIMIT_PER_MIN || '10');
const redisUrl   = $env.REDIS_URL   || '';
const redisToken = $env.REDIS_TOKEN || '';

// ── Helper: Redis GET / SET ───────────────
async function redisGet(key) {
  const r = await $http.request({
    method: 'GET',
    url: `${redisUrl}/get/${key}`,
    headers: { Authorization: `Bearer ${redisToken}` }
  });
  const parsed = JSON.parse(r);
  return parsed.result ? JSON.parse(parsed.result) : null;
}

async function redisSet(key, value, exSeconds) {
  await $http.request({
    method: 'POST',
    url: `${redisUrl}/set/${key}`,
    headers: { Authorization: `Bearer ${redisToken}`, 'Content-Type': 'application/json' },
    body: JSON.stringify({ value: JSON.stringify(value), ex: exSeconds })
  });
}

if (redisUrl && redisToken) {
  try {
    // ── Deduplication via Redis ─────────────
    if (d.message_id) {
      const dedupKey = `dedup:${d.message_id}`;
      const exists   = await redisGet(dedupKey);
      if (exists) {
        return [{ json: { skip: true, reason: 'duplicate', user_id: d.user_id } }];
      }
      await redisSet(dedupKey, 1, 300); // expire after 5 min
    }

    // ── Rate limiting via Redis ─────────────
    const rateKey    = `rate:${d.user_id}`;
    const timestamps = (await redisGet(rateKey)) || [];
    const recent     = timestamps.filter(t => now - t < 60000);
    if (recent.length >= rateLimit) {
      return [{ json: { skip: true, reason: 'rate_limit', user_id: d.user_id } }];
    }
    recent.push(now);
    await redisSet(rateKey, recent, 120); // expire after 2 min

  } catch(e) {
    console.warn('Redis dedup failed — falling back to static data:', e.message);
    // Fall through to static data fallback below
  }
} else {
  // ── Fallback: static data (lost on restart) ─
  try {
    const state = $getWorkflowStaticData('global');
    if (!state.seen)  state.seen  = {};
    if (!state.rates) state.rates = {};

    if (d.message_id && state.seen[d.message_id] && (now - state.seen[d.message_id]) < 300000) {
      return [{ json: { skip: true, reason: 'duplicate', user_id: d.user_id } }];
    }
    if (d.message_id) state.seen[d.message_id] = now;
    for (const id in state.seen) {
      if (now - state.seen[id] > 600000) delete state.seen[id];
    }

    if (!state.rates[d.user_id]) state.rates[d.user_id] = [];
    state.rates[d.user_id] = state.rates[d.user_id].filter(t => now - t < 60000);
    if (state.rates[d.user_id].length >= rateLimit) {
      return [{ json: { skip: true, reason: 'rate_limit', user_id: d.user_id } }];
    }
    state.rates[d.user_id].push(now);
  } catch(e) {
    console.warn('Dedup/rate state error (non-fatal):', e.message);
  }
}

return [$input.first()];

// ══════════════════════════════════════════
// LOAD CONVERSATION HISTORY — v4 Strong Memory
// Short-term: Redis (last 50 messages)
// Long-term:  Supabase (full history summary)
// ══════════════════════════════════════════
const d = $input.first().json;
const redisUrl   = $env.REDIS_URL   || '';
const redisToken = $env.REDIS_TOKEN || '';
const supaUrl    = $env.SUPABASE_URL || '';
const supaKey    = $env.SUPABASE_KEY || '';

let history     = [];
let userProfile = {};

// ── 1. Short-term memory: Redis ───────────────────
if (redisUrl && redisToken) {
  try {
    const r = await $http.request({
      method: 'GET',
      url: `${redisUrl}/get/history:${d.user_id}`,
      headers: { Authorization: `Bearer ${redisToken}` }
    });
    const parsed = JSON.parse(r);
    if (parsed.result) history = JSON.parse(parsed.result) || [];
  } catch(e) {
    console.warn('Redis history load failed:', e.message);
    // Fallback to static data
    try {
      const state = $getWorkflowStaticData('global');
      history = (state.history || {})[d.user_id] || [];
    } catch(e2) {}
  }
} else {
  try {
    const state = $getWorkflowStaticData('global');
    history = (state.history || {})[d.user_id] || [];
  } catch(e) {}
}

// Keep last 50 exchanges in short-term
if (history.length > 50) history = history.slice(-50);

// ── 2. Long-term memory: User profile from Supabase ──
if (supaUrl && supaKey) {
  try {
    const r = await $http.request({
      method: 'GET',
      url: `${supaUrl}/rest/v1/users?user_id=eq.${encodeURIComponent(d.user_id)}&select=*`,
      headers: { 'apikey': supaKey, 'Authorization': `Bearer ${supaKey}` }
    });
    const users = JSON.parse(r);
    if (users && users.length > 0) {
      userProfile = users[0];
    }
  } catch(e) {
    console.warn('User profile load failed (non-fatal):', e.message);
  }
}

// ── 3. Build memory context summary ──────────────
const totalMessages  = userProfile.total_messages || 0;
const preferredLang  = userProfile.language || 'ar';
const userNotes      = userProfile.notes || '';

const memoryContext = totalMessages > 0
  ? `[ملاحظة: هذا المستخدم تواصل معك ${totalMessages} مرة سابقاً. لغته المفضلة: ${preferredLang}.${userNotes ? ' ' + userNotes : ''}]`
  : '';

return [{ json: { ...d, history, userProfile, memoryContext, preferredLang } }];

