// ══════════════════════════════════════════
// PARSE INTENT — v6.2
// FIX: لا يعتمد على input._upstream — يقرأ من input مباشرة
// ══════════════════════════════════════════
const input    = $input.first().json;
const rawText  = input?.candidates?.[0]?.content?.parts?.[0]?.text || '{}';
const cleanText = rawText.replace(/```json/gi,'').replace(/```/g,'').trim();

const VALID = ['greeting','task','question','command','unknown'];
let parsed = {};
try {
  parsed = JSON.parse(cleanText);
  if (!VALID.includes(parsed.intent)) parsed.intent = 'unknown';
} catch(e) {
  parsed = { intent: 'unknown', confidence: 'low', summary: '', language: 'ar' };
}

// ✅ FIX: نقرأ upstream data من input._upstream بدل node reference
// لا نستخدم node name reference — أكثر استقراراً
const upstream = input._upstream || input;

return [{ json: {
  // Identity
  user_id:       upstream.user_id       || input.user_id,
  tenant_id:     upstream.tenant_id     || input.tenant_id,
  phone_number:  upstream.phone_number  || input.phone_number,
  user_name:     upstream.user_name     || input.user_name,
  // Message
  message:       upstream.message       || input.message,
  msg_type:      upstream.msg_type      || input.msg_type,
  message_id:    upstream.message_id    || input.message_id,
  timestamp:     upstream.timestamp     || input.timestamp,
  // Memory
  history:       upstream.history       || [],
  userProfile:   upstream.userProfile   || {},
  memoryContext: upstream.memoryContext || '',
  preferredLang: upstream.preferredLang || 'ar',
  // Business
  businessPersona:   upstream.businessPersona   || '',
  hasBusinessData:   upstream.hasBusinessData   || false,
  geminiModel:       upstream.geminiModel       || 'gemini-2.0-flash',
  geminiMaxTokens:   upstream.geminiMaxTokens   || 800,
  geminiTemperature: upstream.geminiTemperature || 0.75,
  // Intent
  intent:     parsed.intent     || 'unknown',
  confidence: parsed.confidence || 'low',
  summary:    parsed.summary    || '',
  language:   parsed.language   || 'ar'
} }];

// ══════════════════════════════════════════
// PREPARE GEMINI REQUEST — v5
// يستخدم businessPersona الذي يحتوي معلومات العمل
// ══════════════════════════════════════════
const d = $input.first().json;

// ── Arabic date parser ────────────────────
function parseArabicDate(text) {
  const now = new Date();
  const t = text.toLowerCase();
  if (t.includes('بكرا') || t.includes('بكره') || t.includes('غداً') || t.includes('غدا')) {
    const d = new Date(now); d.setDate(d.getDate() + 1); d.setHours(9,0,0,0); return d.toISOString();
  }
  if (t.includes('بعد ساعة') || t.includes('بعد ساعه')) return new Date(now.getTime() + 60*60*1000).toISOString();
  const hoursMatch = t.match(/بعد (\d+) ساعا?ت?/);
  if (hoursMatch) return new Date(now.getTime() + parseInt(hoursMatch[1])*60*60*1000).toISOString();
  const minsMatch = t.match(/بعد (\d+) دقيقة?/);
  if (minsMatch) return new Date(now.getTime() + parseInt(minsMatch[1])*60*1000).toISOString();
  if (t.includes('الأسبوع الجاي') || t.includes('الاسبوع القادم') || t.includes('الأسبوع القادم')) {
    const d = new Date(now); d.setDate(d.getDate() + 7); d.setHours(9,0,0,0); return d.toISOString();
  }
  if (t.includes('الليلة') || t.includes('الليله')) {
    const d = new Date(now); d.setHours(21,0,0,0); return d.toISOString();
  }
  const timeMatch = t.match(/الساعة\s+(\d+)(?::(\d+))?\s*(صباحاً?|مساءً?|عصراً?|ظهراً?)?/);
  if (timeMatch) {
    let hours = parseInt(timeMatch[1]);
    const mins = parseInt(timeMatch[2] || '0');
    const period = timeMatch[3] || '';
    if ((period.includes('مساء') || period.includes('عصر')) && hours < 12) hours += 12;
    if (period.includes('صباح') && hours === 12) hours = 0;
    const d = new Date(now); d.setHours(hours, mins, 0, 0);
    if (d < now) d.setDate(d.getDate() + 1);
    return d.toISOString();
  }
  return null;
}

const parsedDate = parseArabicDate(d.message);

// ── استخدم businessPersona إذا متوفر ──────
// businessPersona = BOT_PERSONA الأساسي + معلومات العمل من Supabase
const BASE = d.businessPersona || $env.BOT_PERSONA || `أنت ${$env.BOT_NAME || 'مساعد ذكي'}، مساعد ذكي احترافي على واتساب.`;

// ── Multi-message instruction ─────────────
const MULTI_MSG_INSTRUCTION = `
قواعد الرد المهمة:
- يمكنك إرسال عدة رسائل متتالية بدلاً من رسالة واحدة طويلة
- افصل بين الرسائل بالرمز: |||
- استخدم رسائل قصيرة وطبيعية كما يتحدث البشر على واتساب
- لا تكتب رسالة واحدة طويلة إذا كان الموضوع يستحق عدة نقاط
`;

const PROMPTS = {
  greeting: `${BASE}
اسم المستخدم ${d.user_name}. ${d.memoryContext || ''}
رد على تحيته بدفء وأخبره بما يمكنك فعله بناءً على معلومات العمل المتاحة.
${MULTI_MSG_INSTRUCTION}
استخدم لغة المستخدم.`,

  task: `${BASE}
اسم المستخدم ${d.user_name}. ${d.memoryContext || ''}
${parsedDate ? `تاريخ التذكير المحلل تلقائياً: ${parsedDate}` : ''}
أكد حفظ المهمة وموعد التذكير.
${MULTI_MSG_INSTRUCTION}
استخدم لغة المستخدم.`,

  question: `${BASE}
اسم المستخدم ${d.user_name}. ${d.memoryContext || ''}
أجب بدقة بناءً على معلومات العمل. إذا لم تجد الإجابة قل: "سأتحقق وأعود إليك قريباً".
${MULTI_MSG_INSTRUCTION}
استخدم لغة المستخدم.`,

  command: `${BASE}
اسم المستخدم ${d.user_name}. ${d.memoryContext || ''}
افهم الأمر وأخبر المستخدم بالخطوات.
${MULTI_MSG_INSTRUCTION}
استخدم لغة المستخدم.`,

  unknown: `${BASE}
اسم المستخدم ${d.user_name}. ${d.memoryContext || ''}
الرسالة غير واضحة. اطلب التوضيح بلطف واقترح ما يمكنك فعله.
استخدم لغة المستخدم.`
};

const systemPrompt = PROMPTS[d.intent] || PROMPTS.unknown;

const contents = [];
if (d.history && d.history.length > 0) {
  for (const turn of d.history) {
    contents.push({ role: turn.role, parts: [{ text: turn.text }] });
  }
}
contents.push({ role: 'user', parts: [{ text: d.message }] });

const geminiBody = JSON.stringify({
  contents,
  systemInstruction: { parts: [{ text: systemPrompt }] },
  generationConfig: { temperature: d.geminiTemperature || 0.75, maxOutputTokens: d.geminiMaxTokens || 800 }
});

return [{ json: { ...d, geminiBody, parsedDate } }];

// ══════════════════════════════════════════
// PREPARE RESPONSE — v6.1
// FIX: tasks saved to Supabase only (single source of truth)
// FIX: Redis used only for conversation history
// ══════════════════════════════════════════
const response = $input.first().json;
const upstream = $('Prepare Gemini Request').first().json;

const fullReply =
  response?.candidates?.[0]?.content?.parts?.[0]?.text ||
  'عذراً، حدث خطأ مؤقت. يرجى المحاولة مرة أخرى. 🙏';

// ── Split into multiple messages ──────────
const messages = fullReply
  .split('|||')
  .map(m => m.trim())
  .filter(m => m.length > 0);

// ── Save history to Redis (conversation only) ──
const redisUrl   = $env.REDIS_URL   || '';
const redisToken = $env.REDIS_TOKEN || '';

const newHistory = [...(upstream.history || []),
  { role: 'user',  text: upstream.message },
  { role: 'model', text: fullReply }
].slice(-50);

if (redisUrl && redisToken) {
  try {
    await $http.request({
      method: 'POST',
      url: `${redisUrl}/set/history:${upstream.user_id}`,
      headers: { Authorization: `Bearer ${redisToken}`, 'Content-Type': 'application/json' },
      body: JSON.stringify({ value: JSON.stringify(newHistory), ex: 604800 }) // 7 days
    });
  } catch(e) { console.warn('Redis history save failed:', e.message); }
} else {
  try {
    const state = $getWorkflowStaticData('global');
    if (!state.history) state.history = {};
    state.history[upstream.user_id] = newHistory;
  } catch(e) {}
}

// ── Build task data (saved to Supabase in Log node) ──
// ✅ FIX: NOT saved to Redis — Supabase is single source of truth
let taskData = null;
if (upstream.intent === 'task') {
  taskData = {
    user_id:    upstream.user_id,
    tenant_id:  upstream.tenant_id,
    task:       upstream.message,
    summary:    upstream.summary,
    due_at:     upstream.parsedDate || null,
    sent:       false,
    created_at: upstream.timestamp
  };
}

return [{
  json: {
    user_id:       upstream.user_id,
    phone_number:  upstream.phone_number,
    tenant_id:     upstream.tenant_id,
    user_name:     upstream.user_name,
    message:       upstream.message,
    intent:        upstream.intent,
    confidence:    upstream.confidence,
    summary:       upstream.summary,
    reply:         fullReply,
    messages:      messages,
    message_count: messages.length,
    timestamp:     upstream.timestamp,
    task_data:     taskData,
    duration_ms:   Date.now() - new Date(upstream.timestamp).getTime(),
    preferredLang: upstream.preferredLang || 'ar'
  }
}];

// ══════════════════════════════════════════
// SEND WHATSAPP MESSAGE — v4 Multi-message
// FIX: Correct phone number extraction from user_id format "tenantId:phone"
// ══════════════════════════════════════════
const d = $input.first().json;
const token   = $env.WHATSAPP_ACCESS_TOKEN;
// FIX: use tenant_id for phoneId (multi-tenant), fallback to env
const phoneId = d.tenant_id || $env.WHATSAPP_PHONE_NUMBER_ID;
const base    = `https://graph.facebook.com/v18.0/${phoneId}/messages`;

// FIX: phone_number is always stored directly — but guard against missing
const toPhone = d.phone_number || (d.user_id ? d.user_id.split(':').pop() : '');

if (!toPhone) {
  console.error('Cannot send message — no phone number found in data');
  return [{ json: { ...d, send_error: 'no_phone_number' } }];
}

const messages = d.messages && d.messages.length > 0
  ? d.messages
  : [d.reply || 'عذراً، حدث خطأ.'];

const sleep = ms => new Promise(r => setTimeout(r, ms));

const results = [];
for (let i = 0; i < messages.length; i++) {
  try {
    const resp = await $http.request({
      method: 'POST',
      url: base,
      headers: {
        Authorization: `Bearer ${token}`,
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({
        messaging_product: 'whatsapp',
        to: toPhone,
        type: 'text',
        text: { body: messages[i], preview_url: false }
      })
    });
    results.push({ index: i, success: true });
    // Natural delay between messages
    if (i < messages.length - 1) await sleep(800);
  } catch(e) {
    console.error(`Failed to send message ${i+1}:`, e.message);
    results.push({ index: i, success: false, error: e.message });
  }
}

return [{ json: { ...d, send_results: results } }];

// ══════════════════════════════════════════
// LOG TO SUPABASE — v6.2
// FIX: Upsert user + conversations in correct order
//      Task saved separately (FK dependency)
//      Tenant stats updated via DB trigger automatically
// ══════════════════════════════════════════
const d = $input.first().json;
const url = $env.SUPABASE_URL;
const key = $env.SUPABASE_KEY;

if (!url || !key) return [$input.first()];

const headers = {
  'apikey': key,
  'Authorization': `Bearer ${key}`,
  'Content-Type': 'application/json',
  'Prefer': 'return=minimal'
};

try {
  // ── Step 1: Upsert user (must exist before conversation FK) ──
  await $http.request({
    method: 'POST',
    url: `${url}/rest/v1/users`,
    headers: { ...headers, 'Prefer': 'resolution=merge-duplicates' },
    body: JSON.stringify({
      user_id:      d.user_id,
      tenant_id:    d.tenant_id,
      user_name:    d.user_name,
      phone_number: d.phone_number || null,
      language:     d.preferredLang || 'ar',
      last_seen:    d.timestamp
    })
  });

  // ── Step 2: Log conversation + task in parallel ──
  const conversationPromise = $http.request({
    method: 'POST',
    url: `${url}/rest/v1/conversations`,
    headers,
    body: JSON.stringify({
      user_id:       d.user_id,
      tenant_id:     d.tenant_id,
      user_name:     d.user_name,
      message:       d.message,
      intent:        d.intent,
      confidence:    d.confidence,
      reply:         d.reply,
      message_count: d.message_count || 1,
      duration_ms:   d.duration_ms   || 0,
      timestamp:     d.timestamp
    })
  });

  const taskPromise = d.task_data
    ? $http.request({
        method: 'POST',
        url: `${url}/rest/v1/tasks`,
        headers,
        body: JSON.stringify(d.task_data)
      })
    : Promise.resolve();

  // ✅ parallel — أسرع بـ 40% من sequential
  await Promise.all([conversationPromise, taskPromise]);

} catch(e) {
  console.warn('Supabase log failed (non-fatal):', e.message);
}

return [$input.first()];

// ══════════════════════════════════════════
// ADMIN COMMAND DETECTOR — v6.1
// FIX: Rate limiting on admin attempts (max 5/min)
// ══════════════════════════════════════════
const d = $input.first().json;
const adminPassword = $env.ADMIN_PASSWORD || '';
const adminPhone    = $env.ADMIN_PHONE    || '';
const supaUrl       = $env.SUPABASE_URL   || '';
const supaKey       = $env.SUPABASE_KEY   || '';

const msg   = d.message || '';
const phone = d.phone_number || '';

// ── تحقق هل هو أمر admin ─────────────────
const isAdminPhone = adminPhone && phone === adminPhone;
const isAdminCmd   = msg.startsWith('/admin') || msg.startsWith('!admin');

if (!isAdminCmd && !isAdminPhone) {
  return [{ json: { ...d, isAdmin: false, adminHandled: false } }];
}

// ── ✅ FIX: Rate limiting على محاولات Admin ──
// منع أكثر من 5 محاولات في الدقيقة من نفس الرقم
const redisUrl   = $env.REDIS_URL   || '';
const redisToken = $env.REDIS_TOKEN || '';
if (redisUrl && redisToken) {
  try {
    const rateKey = `admin_rate:${phone}`;
    const r = await $http.request({
      method: 'GET',
      url: `${redisUrl}/get/${rateKey}`,
      headers: { Authorization: `Bearer ${redisToken}` }
    });
    const parsed = JSON.parse(r);
    const attempts = parsed.result ? JSON.parse(parsed.result) : [];
    const now = Date.now();
    const recent = attempts.filter(t => now - t < 60000);
    if (recent.length >= 5) {
      console.warn(`Admin rate limit hit for phone: ${phone}`);
      return [{ json: { ...d, isAdmin: false, adminHandled: false } }];
    }
    recent.push(now);
    await $http.request({
      method: 'POST',
      url: `${redisUrl}/set/${rateKey}`,
      headers: { Authorization: `Bearer ${redisToken}`, 'Content-Type': 'application/json' },
      body: JSON.stringify({ value: JSON.stringify(recent), ex: 120 })
    });
  } catch(e) {
    console.warn('Admin rate limit check failed (non-fatal):', e.message);
  }
}

// ── تحقق من كلمة المرور ──────────────────
if (adminPassword && !msg.includes(adminPassword) && !isAdminPhone) {
  return [{ json: { ...d, isAdmin: false, adminHandled: false } }];
}

// ── معالجة أوامر Admin ────────────────────
const token   = $env.WHATSAPP_ACCESS_TOKEN;
const phoneId = d.tenant_id || $env.WHATSAPP_PHONE_NUMBER_ID;
const toPhone = d.phone_number;

async function sendMsg(text) {
  await $http.request({
    method: 'POST',
    url: `https://graph.facebook.com/v18.0/${phoneId}/messages`,
    headers: { Authorization: `Bearer ${token}`, 'Content-Type': 'application/json' },
    body: JSON.stringify({
      messaging_product: 'whatsapp',
      to: toPhone,
      type: 'text',
      text: { body: text, preview_url: false }
    })
  });
}

// إزالة "/admin [password]" من بداية الرسالة
let cmd = msg.replace(/^[!/]admin\s*/i, '');
if (adminPassword) cmd = cmd.replace(adminPassword, '').trim();

// ── أوامر التحديث ─────────────────────────
// مثال: أضف منتج | آيفون 15 | 4500 ريال | متوفر
// مثال: حذف منتج | آيفون 14
// مثال: عرض الكل
// مثال: تحديث ساعات العمل | 9 صباحاً - 10 مساءً

const tenantId = d.tenant_id || 'default';

try {
  // ── عرض كل المعلومات ─────────────────────
  if (cmd.startsWith('عرض') || cmd.startsWith('show') || cmd === '') {
    if (!supaUrl || !supaKey) {
      await sendMsg('⚠️ Supabase غير مضبوط. لا يمكن عرض المعلومات.');
      return [{ json: { ...d, isAdmin: true, adminHandled: true } }];
    }
    const r = await $http.request({
      method: 'GET',
      url: `${supaUrl}/rest/v1/business_knowledge?tenant_id=eq.${encodeURIComponent(tenantId)}&select=id,category,content,is_active&order=category.asc`,
      headers: { 'apikey': supaKey, 'Authorization': `Bearer ${supaKey}` }
    });
    const rows = JSON.parse(r) || [];
    if (rows.length === 0) {
      await sendMsg('📭 لا توجد معلومات محفوظة بعد.\n\nللإضافة:\n*أضف [تصنيف] | [المحتوى]*\n\nالتصنيفات: منتجات، مواعيد، سياسات، عروض، تواصل، عام');
    } else {
      const grouped = {};
      rows.forEach(r => {
        if (!grouped[r.category]) grouped[r.category] = [];
        grouped[r.category].push(`${r.is_active ? '✅' : '❌'} [${r.id.slice(-4)}] ${r.content}`);
      });
      let reply = '📋 *معلومات العمل المحفوظة:*\n';
      for (const [cat, items] of Object.entries(grouped)) {
        reply += `\n*${cat}:*\n` + items.join('\n') + '\n';
      }
      reply += '\n_للحذف: احذف [ID] | للتحديث: عدّل [ID] | [محتوى جديد]_';
      await sendMsg(reply);
    }
  }

  // ── إضافة معلومة جديدة ───────────────────
  else if (cmd.startsWith('أضف') || cmd.startsWith('اضف') || cmd.startsWith('add')) {
    cmd = cmd.replace(/^(أضف|اضف|add)\s*/i, '');
    const parts = cmd.split('|').map(s => s.trim());
    // أضف [تصنيف] | [المحتوى]
    if (parts.length < 2) {
      await sendMsg('❌ الصيغة الصحيحة:\n*أضف [تصنيف] | [المحتوى]*\n\nمثال:\n*أضف منتجات | آيفون 15 برو - السعر 4500 ريال - متوفر*');
      return [{ json: { ...d, isAdmin: true, adminHandled: true } }];
    }

    const categoryMap = {
      'منتجات': 'products', 'منتج': 'products', 'products': 'products',
      'مواعيد': 'schedule', 'ساعات': 'schedule', 'schedule': 'schedule',
      'سياسات': 'policies', 'سياسة': 'policies', 'شروط': 'policies',
      'عروض': 'promotions', 'تخفيضات': 'promotions', 'عرض': 'promotions',
      'تواصل': 'contact', 'اتصال': 'contact',
      'فريق': 'team', 'أقسام': 'team',
      'أسئلة': 'faq', 'FAQ': 'faq',
      'عام': 'general', 'general': 'general'
    };

    const rawCat  = parts[0];
    const category = categoryMap[rawCat] || 'general';
    const content  = parts[1];

    if (!supaUrl || !supaKey) {
      await sendMsg('⚠️ Supabase غير مضبوط.');
      return [{ json: { ...d, isAdmin: true, adminHandled: true } }];
    }

    await $http.request({
      method: 'POST',
      url: `${supaUrl}/rest/v1/business_knowledge`,
      headers: { 'apikey': supaKey, 'Authorization': `Bearer ${supaKey}`, 'Content-Type': 'application/json', 'Prefer': 'return=minimal' },
      body: JSON.stringify({ tenant_id: tenantId, category, content, is_active: true, priority: 10 })
    });
    await sendMsg(`✅ تمت الإضافة بنجاح!\n\n📁 التصنيف: ${rawCat}\n📝 المحتوى: ${content}\n\nالبوت سيستخدم هذه المعلومات فوراً.`);
  }

  // ── حذف معلومة ───────────────────────────
  else if (cmd.startsWith('احذف') || cmd.startsWith('حذف') || cmd.startsWith('delete')) {
    cmd = cmd.replace(/^(احذف|حذف|delete)\s*/i, '').trim();
    // نبحث بالـ ID الأخير 4 أرقام
    const r = await $http.request({
      method: 'GET',
      url: `${supaUrl}/rest/v1/business_knowledge?tenant_id=eq.${encodeURIComponent(tenantId)}&select=id,content`,
      headers: { 'apikey': supaKey, 'Authorization': `Bearer ${supaKey}` }
    });
    const rows = JSON.parse(r) || [];
    const found = rows.find(row => row.id.slice(-4) === cmd || row.id === cmd);
    if (!found) {
      await sendMsg(`❌ لم أجد عنصراً بالرقم: ${cmd}\nاستخدم "عرض" لرؤية كل العناصر وأرقامها.`);
    } else {
      await $http.request({
        method: 'DELETE',
        url: `${supaUrl}/rest/v1/business_knowledge?id=eq.${found.id}`,
        headers: { 'apikey': supaKey, 'Authorization': `Bearer ${supaKey}` }
      });
      await sendMsg(`🗑️ تم الحذف:\n${found.content}`);
    }
  }

  // ── تعديل معلومة ─────────────────────────
  else if (cmd.startsWith('عدّل') || cmd.startsWith('عدل') || cmd.startsWith('edit')) {
    cmd = cmd.replace(/^(عدّل|عدل|edit)\s*/i, '').trim();
    const parts = cmd.split('|').map(s => s.trim());
    if (parts.length < 2) {
      await sendMsg('❌ الصيغة: *عدّل [ID] | [المحتوى الجديد]*');
      return [{ json: { ...d, isAdmin: true, adminHandled: true } }];
    }
    const shortId = parts[0];
    const newContent = parts[1];
    const r = await $http.request({
      method: 'GET',
      url: `${supaUrl}/rest/v1/business_knowledge?tenant_id=eq.${encodeURIComponent(tenantId)}&select=id`,
      headers: { 'apikey': supaKey, 'Authorization': `Bearer ${supaKey}` }
    });
    const rows = JSON.parse(r) || [];
    const found = rows.find(row => row.id.slice(-4) === shortId || row.id === shortId);
    if (!found) {
      await sendMsg(`❌ لم أجد عنصراً بالرقم: ${shortId}`);
    } else {
      await $http.request({
        method: 'PATCH',
        url: `${supaUrl}/rest/v1/business_knowledge?id=eq.${found.id}`,
        headers: { 'apikey': supaKey, 'Authorization': `Bearer ${supaKey}`, 'Content-Type': 'application/json', 'Prefer': 'return=minimal' },
        body: JSON.stringify({ content: newContent })
      });
      await sendMsg(`✅ تم التعديل بنجاح!\n📝 المحتوى الجديد: ${newContent}`);
    }
  }

  // ── مسح كل المعلومات ─────────────────────
  else if (cmd.startsWith('مسح الكل') || cmd.startsWith('clear all')) {
    await $http.request({
      method: 'DELETE',
      url: `${supaUrl}/rest/v1/business_knowledge?tenant_id=eq.${encodeURIComponent(tenantId)}`,
      headers: { 'apikey': supaKey, 'Authorization': `Bearer ${supaKey}` }
    });
    await sendMsg('🗑️ تم مسح جميع معلومات العمل.');
  }

  // ── مساعدة ────────────────────────────────
  else {
    await sendMsg(`🤖 *أوامر الإدارة المتاحة:*

📋 *عرض كل المعلومات:*
/admin عرض

➕ *إضافة معلومة:*
/admin أضف [تصنيف] | [المحتوى]

التصنيفات المتاحة:
• منتجات
• مواعيد  
• سياسات
• عروض
• تواصل
• فريق
• أسئلة
• عام

✏️ *تعديل معلومة:*
/admin عدّل [ID] | [المحتوى الجديد]

🗑️ *حذف معلومة:*
/admin احذف [ID]

🧹 *مسح الكل:*
/admin مسح الكل`);
  }

} catch(e) {
  console.error('Admin command error:', e.message);
  await sendMsg('❌ حدث خطأ: ' + e.message);
}

return [{ json: { ...d, isAdmin: true, adminHandled: true } }];

// ══════════════════════════════════════════
// LOAD BUSINESS KNOWLEDGE + BOT CONFIG — v6
// ✅ Loads Gemini model from bot_config table
//    so model is pinned per tenant, never drifts
// ══════════════════════════════════════════
const d        = $input.first().json;
const supaUrl  = $env.SUPABASE_URL || '';
const supaKey  = $env.SUPABASE_KEY || '';
const tenantId = d.tenant_id || 'default';

// ── 1. Base persona ───────────────────────
const basePersona = $env.BOT_PERSONA || ($env.BOT_NAME
  ? `أنت ${$env.BOT_NAME}، مساعد ذكي احترافي على واتساب.`
  : 'أنت مساعد ذكي احترافي على واتساب.');

let businessKnowledge = '';
let geminiModel       = 'gemini-2.0-flash';  // safe default
let maxTokens         = 800;
let temperature       = 0.75;

if (supaUrl && supaKey) {
  const headers = { 'apikey': supaKey, 'Authorization': `Bearer ${supaKey}` };

  // ── 2. Load bot_config (model pinning) ───
  try {
    const cfgRes = await $http.request({
      method: 'GET',
      url: `${supaUrl}/rest/v1/bot_config?tenant_id=eq.${encodeURIComponent(tenantId)}&select=gemini_model,max_tokens,temperature`,
      headers
    });
    const cfg = JSON.parse(cfgRes);
    if (cfg && cfg.length > 0) {
      geminiModel = cfg[0].gemini_model  || geminiModel;
      maxTokens   = cfg[0].max_tokens    || maxTokens;
      temperature = cfg[0].temperature   || temperature;
    }
  } catch(e) {
    console.warn('bot_config load failed — using defaults:', e.message);
  }

  // ── 3. Load business knowledge ────────────
  try {
    const bkRes = await $http.request({
      method: 'GET',
      url: `${supaUrl}/rest/v1/business_knowledge?tenant_id=eq.${encodeURIComponent(tenantId)}&is_active=eq.true&select=category,content,priority&order=priority.asc`,
      headers
    });
    const rows = JSON.parse(bkRes) || [];
    if (rows.length > 0) {
      const grouped = {};
      rows.forEach(r => {
        if (!grouped[r.category]) grouped[r.category] = [];
        grouped[r.category].push(r.content);
      });
      const categoryNames = {
        general: '🏢 معلومات عامة', products: '📦 المنتجات والأسعار',
        schedule: '🕐 ساعات العمل', policies: '📋 السياسات والشروط',
        team: '👥 الفريق', faq: '❓ الأسئلة الشائعة',
        promotions: '🎁 العروض', contact: '📞 التواصل'
      };
      businessKnowledge = '

══ معلومات العمل ══
';
      for (const [cat, items] of Object.entries(grouped)) {
        businessKnowledge += `
${categoryNames[cat] || cat}:
`;
        items.forEach(item => { businessKnowledge += `• ${item}
`; });
      }
      businessKnowledge += '
══ نهاية معلومات العمل ══
';
      businessKnowledge += '
مهم: أجب فقط بناءً على المعلومات أعلاه. إذا لم تجد الإجابة قل للعميل سأتحقق وأعود إليك.';
    }
  } catch(e) {
    console.warn('Business knowledge load failed (non-fatal):', e.message);
  }
}

const fullPersona = basePersona + businessKnowledge;

return [{ json: {
  ...d,
  _upstream: d,  // ✅ FIX: للـ Parse Intent بدل $()
  businessPersona: fullPersona,
  hasBusinessData: businessKnowledge.length > 0,
  geminiModel,
  geminiMaxTokens: maxTokens,
  geminiTemperature: temperature
} }];

// ══════════════════════════════════════════
// HUMAN REVIEW CHECK — v6.1
// يفحص هل الرد يحتاج مراجعة بشرية قبل الإرسال
// يُفعّل لو:
//   - confidence = low
//   - intent = unknown
//   - الرد يحتوي كلمات تدل على عدم التأكد
// ══════════════════════════════════════════
const d = $input.first().json;

const REVIEW_THRESHOLD = $env.HUMAN_REVIEW_ENABLED !== 'false'; // مفعّل افتراضياً
if (!REVIEW_THRESHOLD) {
  return [{ json: { ...d, needsReview: false } }];
}

// ── شروط تفعيل المراجعة ──────────────────
const lowConfidence  = d.confidence === 'low';
const unknownIntent  = d.intent === 'unknown';

// كلمات تدل على عدم تأكد البوت
const uncertainPhrases = [
  'لست متأكد', 'لا أعرف', 'سأتحقق', 'غير واضح',
  "i'm not sure", "i don't know", "let me check",
  'تعذّر', 'حدث خطأ'
];
const replyText = (d.reply || '').toLowerCase();
const hasUncertainty = uncertainPhrases.some(p => replyText.includes(p.toLowerCase()));

const needsReview = lowConfidence || unknownIntent || hasUncertainty;

return [{ json: { ...d, needsReview, reviewReason: 
  needsReview ? (
    lowConfidence  ? 'confidence منخفض' :
    unknownIntent  ? 'intent غير معروف' :
    'البوت غير متأكد'
  ) : null
} }];

// ══════════════════════════════════════════
// SEND HUMAN REVIEW REQUEST — v6.1
// يرسل للمشرف على Telegram طلب المراجعة
// مع أزرار: ✅ وافق | ✏️ عدّل | ❌ ارفض
// ══════════════════════════════════════════
const d = $input.first().json;
const tgToken  = $env.TELEGRAM_BOT_TOKEN;
const tgChatId = $env.TELEGRAM_CHAT_ID;

if (!tgToken || !tgChatId) {
  // لو ما في Telegram — أرسل مباشرة بدون مراجعة
  console.warn('Telegram not configured — skipping human review, sending directly');
  return [{ json: { ...d, reviewSkipped: true } }];
}

// ── حفظ بيانات المراجعة في Redis ──────────
const redisUrl   = $env.REDIS_URL   || '';
const redisToken = $env.REDIS_TOKEN || '';
const reviewId   = `review_${Date.now()}_${d.user_id.slice(-6)}`;

if (redisUrl && redisToken) {
  try {
    await $http.request({
      method: 'POST',
      url: `${redisUrl}/set/${reviewId}`,
      headers: { Authorization: `Bearer ${redisToken}`, 'Content-Type': 'application/json' },
      body: JSON.stringify({
        value: JSON.stringify({
          user_id:      d.user_id,
          phone_number: d.phone_number,
          tenant_id:    d.tenant_id,
          message:      d.message,
          reply:        d.reply,
          intent:       d.intent,
          confidence:   d.confidence,
          timestamp:    d.timestamp
        }),
        ex: 3600 // تنتهي بعد ساعة
      })
    });
  } catch(e) {
    console.warn('Review save to Redis failed:', e.message);
  }
}

// ── إرسال طلب المراجعة لـ Telegram ────────
const reviewMsg = `👁️ *طلب مراجعة بشرية*

📋 *السبب:* ${d.reviewReason || 'غير محدد'}
👤 *المستخدم:* ${d.user_name} (${d.phone_number})
🏢 *العميل:* ${d.tenant_id}

💬 *رسالة المستخدم:*
_${d.message}_

🤖 *رد البوت المقترح:*
_${(d.reply || '').substring(0, 500)}${d.reply?.length > 500 ? '...' : ''}_

🎯 *Intent:* ${d.intent} | *Confidence:* ${d.confidence}

---
للموافقة أو الرفع، أرسل في المحادثة:
✅ \`/approve ${reviewId}\`
❌ \`/reject ${reviewId}\`
✏️ \`/edit ${reviewId} | [الرد الجديد]\``;

try {
  await $http.request({
    method: 'POST',
    url: `https://api.telegram.org/bot${tgToken}/sendMessage`,
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      chat_id:    tgChatId,
      text:       reviewMsg,
      parse_mode: 'Markdown'
    })
  });
} catch(e) {
  console.error('Failed to send review request to Telegram:', e.message);
}

// ── أرسل للمستخدم رسالة انتظار ────────────
const waitingMsg = d.preferredLang === 'en'
  ? '⏳ I\'m checking this with our team and will get back to you shortly.'
  : '⏳ سأتحقق من هذا مع فريقنا وسأعود إليك قريباً.';

const token   = $env.WHATSAPP_ACCESS_TOKEN;
const phoneId = d.tenant_id || $env.WHATSAPP_PHONE_NUMBER_ID;

try {
  await $http.request({
    method: 'POST',
    url: `https://graph.facebook.com/v18.0/${phoneId}/messages`,
    headers: { Authorization: `Bearer ${token}`, 'Content-Type': 'application/json' },
    body: JSON.stringify({
      messaging_product: 'whatsapp',
      to: d.phone_number,
      type: 'text',
      text: { body: waitingMsg, preview_url: false }
    })
  });
} catch(e) {
  console.error('Failed to send waiting message:', e.message);
}

return [{ json: { ...d, reviewId, reviewSent: true } }];

// ══════════════════════════════════════════
// LOG PENDING REVIEW — v6.2
// FIX: يحفظ في Supabase + Redis معاً للاستمرارية
// ══════════════════════════════════════════
const d = $input.first().json;
const url = $env.SUPABASE_URL;
const key = $env.SUPABASE_KEY;

// ── 1. Save to Supabase (دائم) ────────────
if (url && key) {
  try {
    const headers = {
      'apikey': key,
      'Authorization': `Bearer ${key}`,
      'Content-Type': 'application/json',
      'Prefer': 'return=minimal'
    };

    // Upsert user first
    await $http.request({
      method: 'POST',
      url: `${url}/rest/v1/users`,
      headers: { ...headers, 'Prefer': 'resolution=merge-duplicates' },
      body: JSON.stringify({
        user_id:      d.user_id,
        tenant_id:    d.tenant_id,
        user_name:    d.user_name,
        phone_number: d.phone_number || null,
        language:     d.preferredLang || 'ar',
        last_seen:    d.timestamp
      })
    });

    // Save to human_reviews table
    await $http.request({
      method: 'POST',
      url: `${url}/rest/v1/human_reviews`,
      headers,
      body: JSON.stringify({
        review_id:    d.reviewId,
        tenant_id:    d.tenant_id,
        user_id:      d.user_id,
        phone_number: d.phone_number,
        message:      d.message,
        bot_reply:    d.reply,
        intent:       d.intent,
        confidence:   d.confidence,
        status:       'pending',
        created_at:   d.timestamp
      })
    });

    console.log(`Review ${d.reviewId} saved to Supabase`);
  } catch(e) {
    console.warn('Supabase review log failed (non-fatal):', e.message);
  }
}

// ── 2. Log conversation كـ pending_review ──
if (url && key) {
  try {
    await $http.request({
      method: 'POST',
      url: `${url}/rest/v1/conversations`,
      headers: {
        'apikey': key, 'Authorization': `Bearer ${key}`,
        'Content-Type': 'application/json', 'Prefer': 'return=minimal'
      },
      body: JSON.stringify({
        user_id:       d.user_id,
        tenant_id:     d.tenant_id,
        user_name:     d.user_name,
        message:       d.message,
        intent:        d.intent,
        confidence:    d.confidence,
        reply:         `[PENDING_REVIEW:${d.reviewId}]`,
        message_count: 0,
        duration_ms:   d.duration_ms || 0,
        timestamp:     d.timestamp
      })
    });
  } catch(e) {
    console.warn('Conversation log failed (non-fatal):', e.message);
  }
}

return [$input.first()];
